import { Component, OnInit, signal } from '@angular/core';
import { CardsService } from '../../services/cards.service';
import { Card } from '../cards.model';
import { CommonModule } from '@angular/common';

@Component({
    selector: 'app-user-cards',
    standalone: true,
    templateUrl: './user-cards.component.html',
    styleUrls: ['./user-cards.component.css'],
    imports: [CommonModule],
})
export class UserCardsComponent implements OnInit {
    isFetching = signal(false);
    userCards = this.cardsService.loadedUserCards;

    constructor(public cardsService: CardsService) {}

    ngOnInit() {
        this.isFetching.set(true);
        this.cardsService.updateFallbackMessage();

        try {
            this.cardsService.loadUserCards();
        } catch (err: any) {
            console.error('Error loading user cards:', err);
        } finally {
            this.isFetching.set(false);
            this.cardsService.updateFallbackMessage();
        }
    }

    onRemoveCard(card: Card) {
        try {
            this.cardsService.removeUserCard(card);
            console.log(`Card "${card.title}" removed successfully.`);
            this.cardsService.updateFallbackMessage();
        } catch (err: any) {
            console.error('Error removing card:', err);
        }
    }

    trackById(index: number, card: Card): string {
        return card.id;
    }


}
<div class="user-cards-section">
    <!-- Dynamic Fallback Text -->
    <p class="fallback-text" *ngIf="cardsService.fallbackMessage">
        {{ cardsService.fallbackMessage }}
    </p>

    <!-- User Cards Content -->
    <ng-container *ngIf="!isFetching() && !cardsService.availableCardsFetching">
        <ul *ngIf="userCards().length > 0; else noUserCards">
            <li *ngFor="let card of userCards(); trackBy: trackById" class="card-item user-card-item">
                <button (click)="onRemoveCard(card)">
                    <img 
                        [src]="'assets/cards/' + card.image.src" 
                        [alt]="card.image.alt" 
                        class="user-card-image" 
                    />
                </button>
            </li>
        </ul>

        <!-- No Cards Selected -->
        <ng-template #noUserCards>
            <p class="fallback-text">Complete the Forbidden Assembly</p>
        </ng-template>
    </ng-container>
</div>
